def test_transfer_at_exact_daily_limit_succeeds(api_client, own_accounts, reset_daily_transfers, customer_id):
    src, tgt = own_accounts
    payload = {"source_account_id": src, "target_account_id": tgt, "amount": 25000.00, "currency": "USD"}
    headers = {"Idempotency-Key": str(uuid.uuid4())}
    resp = api_client.post("/transfers/internal", json=payload, headers=headers)
    assert resp.status_code in (200, 201)
    assert resp.json()["status"] == "completed"
    daily_total = api_client.get_daily_transfer_total(customer_id)
    assert daily_total == 25000.00
